package fastfilescrape;

final class Chunker {

    private Chunker() {}

    static void chunk(CharSequence content, int maxBytes, ChunkSink sink) {
        int len = content.length();
        int start = 0;
        int chunkIndex = 0;

        while (start < len) {
            int end = approximateEnd(content, start, maxBytes);
            sink.onChunk(chunkIndex++, content.subSequence(start, end));
            start = end;
        }
    }

    private static int approximateEnd(CharSequence s, int start, int maxBytes) {
        int len = s.length();
        int bytes = 0;
        int i = start;
        int lastNewline = -1;

        while (i < len && bytes <= maxBytes) {
            char c = s.charAt(i);
            bytes += (c <= 0x7F) ? 1 : (c <= 0x7FF ? 2 : 3);
            if (c == '\n') lastNewline = i;
            if (bytes > maxBytes) break;
            i++;
        }

        if (lastNewline > start + 100) {
            return lastNewline + 1;
        }
        return Math.min(i, len);
    }

    interface ChunkSink {
        void onChunk(int chunkIndex, CharSequence chunk);
    }
}

package fastfilescrape;

import java.io.*;
import java.nio.charset.StandardCharsets;
import java.nio.file.*;
import java.util.*;

public final class FastFileScrapeCli {

    private enum Mode { TREE, CONTENT, ALL }
    private enum Format { TEXT, JSONL }

    public static void main(String[] args) throws Exception {
        if (args.length == 0 || hasArg(args, "--help", "-h")) {
            printHelp();
            return;
        }

        Mode mode = parseMode(args);
        Path root = Paths.get(getArgValue(args, "--root", "."));
        List<String> includes = getMulti(args, "--include");
        List<String> excludes = getMulti(args, "--exclude");
        if (includes.isEmpty()) includes = List.of("**/*.java", "**/*.cpp");

        String outPath = getArgValue(args, "--out", "-");
        Format format = "jsonl".equalsIgnoreCase(getArgValue(args, "--format", "text"))
                ? Format.JSONL : Format.TEXT;

        int maxChunkBytes = Integer.parseInt(getArgValue(args, "--max-chunk-bytes", "64000"));
        long maxFileSize = Long.parseLong(getArgValue(args, "--max-file-size", "5000000"));

        Writer out = "-".equals(outPath)
                ? new BufferedWriter(new OutputStreamWriter(System.out, StandardCharsets.UTF_8))
                : Files.newBufferedWriter(Paths.get(outPath), StandardCharsets.UTF_8);

        try (out) {
            if (mode == Mode.TREE || mode == Mode.ALL) {
                FastFileTree.Config tcfg = new FastFileTree.Config();
                tcfg.root = root;
                tcfg.includeGlobs = includes;
                tcfg.excludeGlobs = excludes;

                FastFileTree.Node tree = FastFileTree.build(tcfg);
                if (format == Format.TEXT) {
                    out.write("TREE:\n");
                    FastFileTree.printTree(tree, out);
                    out.write("\n");
                } else {
                    writeTreeJson(tree, out);
                }
            }

            if (mode == Mode.CONTENT || mode == Mode.ALL) {
                FastFileScrapeContent.Config ccfg = new FastFileScrapeContent.Config();
                ccfg.root = root;
                ccfg.includeGlobs = includes;
                ccfg.excludeGlobs = excludes;
                ccfg.maxChunkBytes = maxChunkBytes;
                ccfg.maxFileSizeBytes = maxFileSize;

                if (format == Format.TEXT) {
                    FastFileScrapeContent.scrape(ccfg, (file, chunkIndex, content) -> {
                        out.write("=== " + root.relativize(file) + " (chunk " + chunkIndex + ") ===\n");
                        out.write(content.toString());
                        out.write("\n\n");
                    });
                } else {
                    FastFileScrapeContent.scrape(ccfg, (file, chunkIndex, content) -> {
                        String json = toJsonLine(root.relativize(file).toString(), chunkIndex, content.toString());
                        out.write(json);
                        out.write("\n");
                    });
                }
            }
        }
    }

    private static void printHelp() {
        System.out.println("""
            fastfilescrape [mode] --root <path> [options]

            Modes:
              tree              Structure-only file tree
              content           File contents only
              all               Tree + contents

            Options:
              --root <path>                 Start directory (default: .)
              --include <glob>              Include pattern (repeatable)
              --exclude <glob>              Exclude pattern (repeatable)
              --out <file|->                Output file or - for stdout (default: -)
              --format <text|jsonl>         Output format (default: text)
              --max-chunk-bytes <int>       Chunk size in bytes (default: 64000)
              --max-file-size <long>        Max file size in bytes (default: 5000000)

            Examples:
              fastfilescrape tree --root . --include "**/*.java"
              fastfilescrape content --root . --include "**/*.java" --out repo.txt
              fastfilescrape all --root . --include "**/*.java" --format jsonl --out repo.jsonl
            """);
    }


    private static Mode parseMode(String[] args) {
        if (args.length == 0) return Mode.ALL;
        String m = args[0].toLowerCase(Locale.ROOT);
        return switch (m) {
            case "tree" -> Mode.TREE;
            case "content" -> Mode.CONTENT;
            case "all" -> Mode.ALL;
            default -> Mode.ALL;
        };
    }

    private static boolean hasArg(String[] args, String... keys) {
        for (String a : args) {
            for (String k : keys) {
                if (a.equals(k)) return true;
            }
        }
        return false;
    }

    private static String getArgValue(String[] args, String key, String def) {
        for (int i = 0; i < args.length - 1; i++) {
            if (args[i].equals(key)) return args[i + 1];
        }
        return def;
    }

    private static List<String> getMulti(String[] args, String key) {
        List<String> list = new ArrayList<>();
        for (int i = 0; i < args.length - 1; i++) {
            if (args[i].equals(key)) {
                list.add(args[i + 1]);
            }
        }
        return list;
    }

    private static String escapeJson(String s) {
        StringBuilder sb = new StringBuilder(s.length() + 16);
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            switch (c) {
                case '"' -> sb.append("\\\"");
                case '\\' -> sb.append("\\\\");
                case '\n' -> sb.append("\\n");
                case '\r' -> sb.append("\\r");
                case '\t' -> sb.append("\\t");
                default -> {
                    if (c < 0x20) {
                        sb.append(String.format("\\u%04x", (int) c));
                    } else {
                        sb.append(c);
                    }
                }
            }
        }
        return sb.toString();
    }

    private static String toJsonLine(String path, int chunkIndex, String content) {
        return "{\"path\":\"" + escapeJson(path) + "\"," +
               "\"chunk\":" + chunkIndex + "," +
               "\"content\":\"" + escapeJson(content) + "\"}";
    }

    private static void writeTreeJson(FastFileTree.Node node, Appendable out) throws IOException {
        out.append("{");
        out.append("\"path\":\"").append(escapeJson(node.path.toString())).append("\",");
        out.append("\"dir\":").append(String.valueOf(node.isDirectory)).append(",");
        out.append("\"size\":").append(String.valueOf(node.sizeBytes)).append(",");
        out.append("\"children\":[");
        for (int i = 0; i < node.children.size(); i++) {
            if (i > 0) out.append(",");
            writeTreeJson(node.children.get(i), out);
        }
        out.append("]}");
    }
}

package fastfilescrape;

import java.io.IOException;
import java.nio.charset.Charset;
import java.nio.charset.StandardCharsets;
import java.nio.file.*;
import java.nio.file.attribute.BasicFileAttributes;
import java.util.*;

public final class FastFileScrapeContent {

    public static final class Config {
        public Path root;
        public List<String> includeGlobs = List.of("**/*.java", "**/*.cpp");
        public List<String> excludeGlobs = List.of(".git/**", "build/**", "out/**");
        public int maxChunkBytes = 64_000;
        public long maxFileSizeBytes = 5_000_000;
        public Charset charset = StandardCharsets.UTF_8;
    }

    public interface Sink {
        void onChunk(Path file, int chunkIndex, CharSequence content) throws IOException;
    }

    public static void scrape(Config cfg, Sink sink) throws IOException {
        Objects.requireNonNull(cfg.root, "root");
        GlobMatcher matcher = new GlobMatcher(cfg.includeGlobs, cfg.excludeGlobs, cfg.root);

        Files.walkFileTree(cfg.root, new SimpleFileVisitor<>() {
            @Override
            public FileVisitResult preVisitDirectory(Path dir, BasicFileAttributes attrs) {
                if (!matcher.matchesDir(dir)) {
                    return FileVisitResult.SKIP_SUBTREE;
                }
                return FileVisitResult.CONTINUE;
            }

            @Override
            public FileVisitResult visitFile(Path file, BasicFileAttributes attrs) throws IOException {
                if (!matcher.matchesFile(file)) {
                    return FileVisitResult.CONTINUE;
                }
                if (attrs.size() > cfg.maxFileSizeBytes) {
                    return FileVisitResult.CONTINUE;
                }
                String content = Files.readString(file, cfg.charset);
                Chunker.chunk(content, cfg.maxChunkBytes, (chunkIndex, chunk) -> {
                    try {
                        sink.onChunk(file, chunkIndex, chunk);
                    } catch (IOException e) {
                        throw new RuntimeException(e);
                    }
                });
                return FileVisitResult.CONTINUE;
            }
        });
    }
}

package fastfilescrape;

import java.io.IOException;
import java.nio.file.*;
import java.nio.file.attribute.BasicFileAttributes;
import java.util.*;

public final class FastFileTree {

    public static final class Node {
        public final Path path;
        public final boolean isDirectory;
        public final long sizeBytes;
        public final List<Node> children = new ArrayList<>();

        public Node(Path path, boolean isDirectory, long sizeBytes) {
            this.path = path;
            this.isDirectory = isDirectory;
            this.sizeBytes = sizeBytes;
        }
    }

    public static final class Config {
        public Path root;
        public List<String> includeGlobs = List.of("**/*");
        public List<String> excludeGlobs = List.of(".git/**", "build/**", "out/**");
    }

    public static Node build(Config cfg) throws IOException {
        Objects.requireNonNull(cfg.root, "root");
        GlobMatcher matcher = new GlobMatcher(cfg.includeGlobs, cfg.excludeGlobs, cfg.root);

        Node rootNode = new Node(cfg.root, true, 0L);
        Map<Path, Node> map = new HashMap<>();
        map.put(cfg.root.toAbsolutePath().normalize(), rootNode);

        Files.walkFileTree(cfg.root, new SimpleFileVisitor<>() {
            @Override
            public FileVisitResult preVisitDirectory(Path dir, BasicFileAttributes attrs) {
                if (!matcher.matchesDir(dir)) {
                    return FileVisitResult.SKIP_SUBTREE;
                }
                if (!dir.equals(cfg.root)) {
                    Node parent = map.get(dir.getParent().toAbsolutePath().normalize());
                    if (parent != null) {
                        Node node = new Node(dir, true, 0L);
                        parent.children.add(node);
                        map.put(dir.toAbsolutePath().normalize(), node);
                    }
                }
                return FileVisitResult.CONTINUE;
            }

            @Override
            public FileVisitResult visitFile(Path file, BasicFileAttributes attrs) {
                if (!matcher.matchesFile(file)) {
                    return FileVisitResult.CONTINUE;
                }
                Node parent = map.get(file.getParent().toAbsolutePath().normalize());
                if (parent != null) {
                    Node node = new Node(file, false, attrs.size());
                    parent.children.add(node);
                }
                return FileVisitResult.CONTINUE;
            }
        });

        pruneEmptyDirs(rootNode);
        sortTree(rootNode);
        return rootNode;
    }

    private static boolean pruneEmptyDirs(Node node) {
        if (!node.isDirectory) {
            return false; // files are never pruned
        }

        node.children.removeIf(FastFileTree::pruneEmptyDirs);

        return node.children.isEmpty();
    }


    private static void sortTree(Node node) {
        node.children.sort((a, b) -> {
            if (a.isDirectory && !b.isDirectory) return -1;
            if (!a.isDirectory && b.isDirectory) return 1;
            return a.path.getFileName().toString().compareToIgnoreCase(b.path.getFileName().toString());
        });
        for (Node c : node.children) {
            if (c.isDirectory) sortTree(c);
        }
    }

    public static void printTree(Node node, Appendable out) throws IOException {
        printTree(node, out, "", true, true);
    }

    private static void printTree(Node node, Appendable out, String prefix, boolean isLast, boolean isRoot) throws IOException {
        if (!isRoot) {
            out.append(prefix);
            out.append(isLast ? "└── " : "├── ");
            out.append(node.path.getFileName().toString());
            if (!node.isDirectory) {
                out.append(" (").append(String.valueOf(node.sizeBytes)).append(" bytes)");
            }
            out.append('\n');
            prefix += isLast ? "    " : "│   ";
        }
        for (int i = 0; i < node.children.size(); i++) {
            Node c = node.children.get(i);
            printTree(c, out, prefix, i == node.children.size() - 1, false);
        }
    }
}

package fastfilescrape;

import java.nio.file.*;
import java.util.*;

final class GlobMatcher {

    private final List<PathMatcher> includes;
    private final List<PathMatcher> excludes;
    private final Path root;

    GlobMatcher(List<String> includeGlobs, List<String> excludeGlobs, Path root) {
        FileSystem fs = FileSystems.getDefault();
        this.includes = new ArrayList<>();
        this.excludes = new ArrayList<>();
        for (String g : includeGlobs) {
            includes.add(fs.getPathMatcher("glob:" + g));
        }
        for (String g : excludeGlobs) {
            excludes.add(fs.getPathMatcher("glob:" + g));
        }
        this.root = root.toAbsolutePath().normalize();
    }

    private Path rel(Path p) {
        Path abs = p.toAbsolutePath().normalize();
        return root.relativize(abs);
    }

    boolean matchesDir(Path dir) {
        Path r = rel(dir);

        // If excluded → skip whole subtree
        if (isExcluded(r)) return false;

        // Directories are always allowed unless excluded
        return true;
    }


    boolean matchesFile(Path file) {
        Path r = rel(file);
        if (isExcluded(r)) return false;
        if (includes.isEmpty()) return true;
        for (PathMatcher m : includes) {
            if (m.matches(r)) return true;
        }
        return false;
    }

    private boolean isExcluded(Path r) {
        for (PathMatcher m : excludes) {
            if (m.matches(r)) return true;

            // also check prefix match for directory patterns like ".git/**"
            if (r.toString().startsWith(m.toString().replace("glob:", "").replace("/**", ""))) {
                return true;
            }
        }
        return false;
    }

}
